:"Add wizard-like export view for workflow invocations","user":{"login":"davelopez","id":46503462,"node_id":"MDQ6VXNlcjQ2NTAzNDYy","avatar_url":"https://avatars.githubusercontent.com/u/46503462?v=4","gravatar_id":"","url":"https://api.github.com/users/davelopez","html_url":"https://github.com/davelopez","followers_url":"https://api.github.com/users/davelopez/followers","following_url":"https://api.github.com/users/davelopez/following{/other_user}","gists_url":"https://api.github.com/users/davelopez/gists{/gist_id}","starred_url":"https://api.github.com/users/davelopez/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/davelopez/subscriptions","organizations_url":"https://api.github.com/users/davelopez/orgs","repos_url":"https://api.github.com/users/davelopez/repos","events_url":"https://api.github.com/users/davelopez/events{/privacy}","received_events_url":"https://api.github.com/users/davelopez/received_events","type":"User","site_admin":false},"body":"This is an attempt to make the workflow invocation export process a bit more guided and user-friendly. It also explores using wizard-like interfaces for "complex" processes with many options.

![InvocationWizardFinal](https://github.com/user-attachments/assets/159124a8-27fa-4f2c-b731-d48cdd0b28b3)


If we like this approach we can make it more generic and incorporate it, for example in the history export (and archival process) or in other places where the user has to decide between multiple options, like collection building, etc.

---

## Generic Wizard Usage
I've extracted the basic logic and the base component into `GenericWizard`. Here is a basic example of how to use it.

**MyWizard.vue**
```vue
<script setup lang="ts">
import { reactive, ref } from "vue";

import { useWizard } from "@/components/Common/Wizard/useWizard";

import GenericWizard from "@/components/Common/Wizard/GenericWizard.vue";

// This reactive object holds the data for the entire wizard.
// Use the values in the wizard steps to control the wizard flow
// and to validate the data before submitting.
const wizardData = reactive({
    enableHiddenStep: false,
    confirmDone: false,
});

// Use the useWizard composable to define the wizard steps
const wizard = useWizard({
    intro: {
        label: "Initial Step",
        instructions: "First instructions go here",
        isValid: () => true,
        isSkippable: () => false,
    },
    "optional-step": {
        label: "Optional",
        instructions: "The instructions for the optional step",
        isValid: () => true,
        isSkippable: () => !wizardData.enableHiddenStep,
    },
    end: {
        label: "Final step",
        instructions: "Mark the checkbox to continue",
        isValid: () => wizardData.confirmDone,
        isSkippable: () => false,
    },
});

const submitButtonLabel = ref("Done");
const isBusy = ref(false);

// This function is called when the wizard is completed
async function onWizardSubmit() {
    isBusy.value = true;
    console.log("Wizard submit...", wizardData);
    await new Promise((resolve) => setTimeout(resolve, 2000));
    console.log("Wizard submit DONE");
    isBusy.value = false;
}
</script>

<template>
    <div>
        <GenericWizard
            title="My Simple Wizard"
            :use="wizard"
            :is-busy="isBusy"
            :submit-button-label="submitButtonLabel"
            @submit="onWizardSubmit">
            <!-- To define the content of each step, use the `v-if` directive with 
            the `wizard.isCurrent` method and pass the corresponding step key -->
            <div v-if="wizard.isCurrent('intro')">
                <p>This is the content of the initial step</p>
                <BFormCheckbox v-model="wizardData.enableHiddenStep" switch> Enable Optional Step </BFormCheckbox>
            </div>

            <div v-if="wizard.isCurrent('optional-step')">
                <p>This is the content of the optional step</p>
                <b>Nothing to do here...</b>
            </div>

            <div v-if="wizard.isCurrent('end')">
                <BFormCheckbox v-model="wizardData.confirmDone">
                    Enable the <b>{{ submitButtonLabel }}</b> button
                </BFormCheckbox>
            </div>
        </GenericWizard>
    </div>
</template>
