## Generic Wizard Usage
I've extracted the basic logic and the base component into `GenericWizard`. Here is a basic example of how to use it.

**MyWizard.vue**
```vue
<script setup lang="ts">
import { reactive, ref } from "vue";

import { useWizard } from "@/components/Common/Wizard/useWizard";

import GenericWizard from "@/components/Common/Wizard/GenericWizard.vue";

// This reactive object holds the data for the entire wizard.
// Use the values in the wizard steps to control the wizard flow
// and to validate the data before submitting.
const wizardData = reactive({
    enableHiddenStep: false,
    confirmDone: false,
});

// Use the useWizard composable to define the wizard steps
const wizard = useWizard({
    intro: {
        label: "Initial Step",
        instructions: "First instructions go here",
        isValid: () => true,
        isSkippable: () => false,
    },
    "optional-step": {
        label: "Optional",
        instructions: "The instructions for the optional step",
        isValid: () => true,
        isSkippable: () => !wizardData.enableHiddenStep,
    },
    end: {
        label: "Final step",
        instructions: "Mark the checkbox to continue",
        isValid: () => wizardData.confirmDone,
        isSkippable: () => false,
    },
});

const submitButtonLabel = ref("Done");
const isBusy = ref(false);

// This function is called when the wizard is completed
async function onWizardSubmit() {
    isBusy.value = true;
    console.log("Wizard submit...", wizardData);
    await new Promise((resolve) => setTimeout(resolve, 2000));
    console.log("Wizard submit DONE");
    isBusy.value = false;
}
</script>

<template>
    <div>
        <GenericWizard
            title="My Simple Wizard"
            :use="wizard"
            :is-busy="isBusy"
            :submit-button-label="submitButtonLabel"
            @submit="onWizardSubmit">
            <!-- To define the content of each step, use the `v-if` directive with 
            the `wizard.isCurrent` method and pass the corresponding step key -->
            <div v-if="wizard.isCurrent('intro')">
                <p>This is the content of the initial step</p>
                <BFormCheckbox v-model="wizardData.enableHiddenStep" switch> Enable Optional Step </BFormCheckbox>
            </div>

            <div v-if="wizard.isCurrent('optional-step')">
                <p>This is the content of the optional step</p>
                <b>Nothing to do here...</b>
            </div>

            <div v-if="wizard.isCurrent('end')">
                <BFormCheckbox v-model="wizardData.confirmDone">
                    Enable the <b>{{ submitButtonLabel }}</b> button
                </BFormCheckbox>
            </div>
        </GenericWizard>
    </div>
</template>
```

